BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?container ?containerName ?imp ?impName WHERE {
  ?imp rdf:type ?impType .
  VALUES ?impType { vocab:package%20import vocab:element%20import }
  ?imp vocab:NamedElement_name ?impName .
  FILTER(CONTAINS(LCASE(STR(?impName)), "dorr"))

  ?container vocab:NamedElement_name ?containerName .
  {
    ?container vocab:Element_ownedElement+ ?imp .
  }
  UNION
  {
    ?container vocab:Element_ownedElement ?child .
    ?child vocab:Element_ownedElement+ ?imp .
  }

  FILTER(CONTAINS(LCASE(STR(?containerName)), "aps") || CONTAINS(LCASE(STR(?containerName)), "dor"))
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkg ?pkgName ?uriVal WHERE {
  ?pkg rdf:type vocab:package .
  OPTIONAL { ?pkg vocab:NamedElement_name ?pkgName . }
  OPTIONAL { ?pkg vocab:Package_URI ?uriVal . }
  FILTER(
    (BOUND(?pkgName) && CONTAINS(LCASE(STR(?pkgName)), "dorr")) ||
    (BOUND(?uriVal) && CONTAINS(LCASE(STR(?uriVal)), "dorr"))
  )
}
LIMIT 25
